B.a0J=s(["4 Douglasie-Rahmenh\xf6lzer 90\xd790 (3 m) je auf 2,8 m abl\xe4ngen \u2013 4 durchgehende Bretter f\xfcr 2 Balken (Restst\xfcck 20 cm).","Je Balkenseite 2 Bretter deckungsgleich aufeinanderlegen (untere + obere Lage).","Kontaktfl\xe4chen vollfl\xe4chig mit D4-Leim bestreichen.","Beide Lagen alle ~20 cm mit 8\xd7100-Schrauben (versetzt) verschrauben.","Ergebnis: 2 durchgehende Doppelbalken \xe0 2,8 m \u2013 ohne Stoss."],t.s)
B.a1I=s(["assets/bau/01_doppelbalken.png"],t.s)
B.Ml=new A.eV("doppelbalken","Doppelbalken bauen",B.a0J,"Bretter gerade und b\xfcndig verleimt; keine St\xf6sse.","Durchgehende Bretter = maximale Steifigkeit. Die zwei verleimten Lagen wirken zugleich gegen Verzug \u2013 D4-Leim (wasserfest) vollfl\xe4chig auftragen.",B.a1I)
B.a_d=s(["Fester, sonniger, windgesch\xfctzter Platz; Flugl\xf6cher sp\xe4ter nach S\xfcdost, Flugbahn 2\u20133 m frei, hinten 80\u2013100 cm Arbeitsraum.","Rechteck 2000 \xd7 400 mm anzeichnen: Beinabstand l\xe4ngs 2000 mm, Balkenachse (vorn/hinten) 400 mm.","Beine ~400 mm von den Enden einr\xfccken.","Rechtwinkligkeit mit einer Latten-Lehre und gleichen Diagonalen pr\xfcfen."],t.s)
B.a3_=s(["assets/bau/02_draufsicht_rechteck.png"],t.s)
B.Mv=new A.eV("rechteck","Standort & Rechteck anzeichnen",B.a_d,"Beinabstand 2000 mm, Achse 400 mm, Diagonalen gleich.",null,B.a3_)
B.a1P=s(["4\xd7 Krinner U-FIX 91 an den angezeichneten Punkten ansetzen.","Mit einem Stahlstab durch die Aufnahme lotrecht eindrehen.","Mit der Wasserwaage an der H\xfclse laufend die Senkrechte kontrollieren.","Die 4 Aufnahmen grob auf gleiche H\xf6he bringen (Feinausgleich folgt \xfcber die Bolzen)."],t.s)
B.a0s=s(["assets/bau/03_erdschraube_lot.png"],t.s)
B.Mi=new A.eV("erdschrauben","Erdschrauben eindrehen",B.a1P,"Jede Erdschraube lotrecht; Positionen = angezeichnetes Rechteck.","Auf Steine/Wurzeln achten \u2013 notfalls Schraube leicht versetzen, das Rechteck aber halten.",B.a0s)
B.a1Q=s(["4 Pfosten aus Douglasie 90\xd790 auf ~120 mm zuschneiden.","Je Pfosten in eine U-FIX-Aufnahme stellen.","Seitlich mit 8\xd7100-Schraube durchbolzen."],t.s)
